// TOPIC_CHANNELS 파싱: 채널별 아이템 생성
// 형식: 채널이름/채널ID+채널이름/채널ID+...
const raw = ($env.TOPIC_CHANNELS || '').trim();
if (!raw) {
  return [{ json: { skip: true, reason: 'TOPIC_CHANNELS 미설정' } }];
}

const items = [];
const invalid = [];

for (const chunk of raw.split('+')) {
  const part = (chunk || '').trim();
  if (!part) continue;

  const slashIdx = part.indexOf('/');
  if (slashIdx < 0) {
    invalid.push(`${part}(구분자 '/' 없음)`);
    continue;
  }

  const channelName = part.slice(0, slashIdx).trim();
  const channelId = part.slice(slashIdx + 1).trim();

  if (!channelName || !channelId) {
    invalid.push(`${part}(채널명/채널ID 비어 있음)`);
    continue;
  }

  items.push({ json: { channelId, channelName } });
}

console.log(`[WF-09] parsed channels: valid=${items.length}, invalid=${invalid.length}`);
if (invalid.length) {
  console.log(`[WF-09] invalid TOPIC_CHANNELS entries: ${invalid.join(', ')}`);
}

if (!items.length) {
  return [{ json: { skip: true, reason: '유효한 채널 없음' } }];
}

return items;

// 채널별 active notebook 상태 확인 + YouTube RSS 조회 + seed/최근영상 필터링
const channelId = ($json.channelId || '').trim();
const channelName = ($json.channelName || '').trim();

if (!channelId) {
  return { json: { skip: true, channelId, channelName, reason: 'channelId 없음' } };
}

let notebookState;
try {
  notebookState = await this.helpers.httpRequest({
    method: 'POST',
    url: `${$env.NOTEBOOKLM_SERVICE_URL}/notebook-state`,
    headers: {
      'Content-Type': 'application/json',
      'X-Internal-Secret': $env.GATEWAY_INTERNAL_SECRET,
    },
    body: { channel_id: channelId },
    json: true,
    timeout: 30000,
  });
} catch (e) {
  const msg = e && e.message ? e.message : String(e);
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      reason: `notebook-state 조회 실패(${msg.slice(0, 200)})`,
    },
  };
}

if (!notebookState || notebookState.status !== 'success' || !notebookState.notebook_url) {
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      reason: `active notebook 없음(${(notebookState && notebookState.error) || 'unknown'})`,
    },
  };
}

const notebookUrl = (notebookState.notebook_url || '').trim();
const activeSourceCount = Number.isFinite(Number(notebookState.active_source_count)) ? Number(notebookState.active_source_count) : 0;
const activeReportCount = Number.isFinite(Number(notebookState.active_report_count)) ? Number(notebookState.active_report_count) : 0;
const hasSources = Boolean(notebookState.has_sources);
const hasReports = Boolean(notebookState.has_reports);
const latestSourceUrl = (notebookState.latest_source_url || '').trim();
const latestSourceTitle = (notebookState.latest_source_title || '').trim();
const lookbackRaw = ($env.WF09_LOOKBACK_HOURS || '').trim();
const parsedLookback = Number.parseFloat(lookbackRaw);
const lookbackHours = Number.isFinite(parsedLookback) && parsedLookback > 0 ? parsedLookback : 24;
const CUTOFF_MS = Date.now() - lookbackHours * 60 * 60 * 1000;
const CUTOFF_ISO = new Date(CUTOFF_MS).toISOString();

if (hasSources && !hasReports && latestSourceUrl) {
  return {
    json: {
      videoUrl: latestSourceUrl,
      title: latestSourceTitle,
      publishedAt: '',
      channelId,
      channelName,
      notebookUrl,
      activeSourceCount,
      hasSources,
      activeReportCount,
      hasReports,
      seedMode: 'report-backfill',
      attemptsUsed: 0,
      fetchMode: 'not-required',
      executionMs: 0,
      entriesTotal: 0,
      validEntriesCount: 0,
      cutoffIso: CUTOFF_ISO,
      lookbackHours,
      latestPublishedAt: null,
      freshCount: 0,
      ignoredLookback: true,
      selectedStrategy: 'latest-source-from-notebook-no-report',
      forceAutoReport: true,
    },
  };
}

const seedMode = hasSources ? 'recent-window' : 'initial-empty-notebook';
const rssUrl = `https://www.youtube.com/feeds/videos.xml?channel_id=${channelId}`;
const MAX_ATTEMPTS = 8;
const ATTEMPT_TIMEOUT_MS = 6000;
const MAX_TOTAL_MS = 60000;
const WAIT_MS = [1000, 1500, 2000, 2500, 3000, 4000, 5000];

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const decode = (s = '') => s
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'");

const parseXmlEntries = (xml) => {
  const list = [];
  const re = /<entry>([\s\S]*?)<\/entry>/g;
  let m;
  while ((m = re.exec(xml)) !== null) {
    const block = m[1];
    const videoId = (block.match(/<yt:videoId>([^<]+)<\/yt:videoId>/) || [])[1] || '';
    if (!videoId) continue;
    const title = (block.match(/<title>([^<]+)<\/title>/) || [])[1] || '';
    const publishedAt = (block.match(/<published>([^<]+)<\/published>/) || [])[1] || '';
    const linkMatch = block.match(/<link rel="alternate" href="([^"]+)"/);
    const link = linkMatch ? linkMatch[1] : `https://www.youtube.com/watch?v=${videoId}`;
    list.push({ videoId, title: decode(title), publishedAt, videoUrl: link });
  }
  return list;
};

const asArray = (v) => Array.isArray(v) ? v : (v == null ? [] : [v]);
const textOf = (v) => {
  if (typeof v === 'string') return v;
  if (Array.isArray(v)) return textOf(v[0]);
  if (!v || typeof v !== 'object') return '';
  if (typeof v._ === 'string') return v._;
  if (typeof v['#text'] === 'string') return v['#text'];
  return '';
};
const hrefOf = (linkVal) => {
  for (const l of asArray(linkVal)) {
    if (!l) continue;
    if (typeof l === 'string') return l;
    if (typeof l.href === 'string') return l.href;
    if (l.$ && typeof l.$.href === 'string') return l.$.href;
    if (l.attrs && typeof l.attrs.href === 'string') return l.attrs.href;
  }
  return '';
};
const parseObjEntries = (obj) => {
  const feed = obj && obj.feed ? obj.feed : obj;
  const rows = feed && feed.entry ? asArray(feed.entry) : [];
  const list = [];
  for (const r of rows) {
    if (!r || typeof r !== 'object') continue;
    const videoId = textOf(r['yt:videoId']) || textOf(r.videoId);
    if (!videoId) continue;
    const title = decode(textOf(r.title));
    const publishedAt = textOf(r.published) || textOf(r.updated);
    const link = hrefOf(r.link) || `https://www.youtube.com/watch?v=${videoId}`;
    list.push({ videoId, title, publishedAt, videoUrl: link });
  }
  return list;
};

let attemptsUsed = 0;
let fetchMode = '';
let entries = [];
let lastError = '';
const t0 = Date.now();

for (let attempt = 1; attempt <= MAX_ATTEMPTS; attempt++) {
  attemptsUsed = attempt;
  if (Date.now() - t0 >= MAX_TOTAL_MS) {
    lastError = `실행시간 상한 ${Math.floor(MAX_TOTAL_MS / 1000)}초 도달`;
    break;
  }
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: rssUrl,
      options: { timeout: ATTEMPT_TIMEOUT_MS },
    });
    if (typeof resp === 'string') {
      if (resp.includes('<feed')) {
        entries = parseXmlEntries(resp);
        fetchMode = 'xml-string';
        console.log(`[WF-09] RSS success channel=${channelId} attempt=${attempt} mode=${fetchMode} entries=${entries.length} seedMode=${seedMode}`);
        break;
      }
      lastError = `문자열 응답이나 feed 없음(len=${resp.length})`;
    } else if (resp && typeof resp === 'object') {
      const candidate = (typeof resp.body === 'string' || typeof resp.body === 'object') ? resp.body : resp;
      if (typeof candidate === 'string' && candidate.includes('<feed')) {
        entries = parseXmlEntries(candidate);
        fetchMode = 'xml-string-in-body';
        console.log(`[WF-09] RSS success channel=${channelId} attempt=${attempt} mode=${fetchMode} entries=${entries.length} seedMode=${seedMode}`);
        break;
      }
      if (candidate && typeof candidate === 'object' && (candidate.feed || candidate.entry)) {
        entries = parseObjEntries(candidate);
        fetchMode = 'parsed-object';
        console.log(`[WF-09] RSS success channel=${channelId} attempt=${attempt} mode=${fetchMode} entries=${entries.length} seedMode=${seedMode}`);
        break;
      }
      lastError = '객체 응답이나 feed/entry 구조 없음';
    } else {
      lastError = `지원되지 않는 응답 타입(${typeof resp})`;
    }
  } catch (e) {
    lastError = e && e.message ? e.message : String(e);
    console.log(`[WF-09] RSS error channel=${channelId} attempt=${attempt}: ${lastError}`);
  }
  if (attempt < MAX_ATTEMPTS) {
    const elapsed = Date.now() - t0;
    if (elapsed >= MAX_TOTAL_MS) {
      lastError = `실행시간 상한 ${Math.floor(MAX_TOTAL_MS / 1000)}초 도달`;
      break;
    }
    const wait = WAIT_MS[Math.min(attempt - 1, WAIT_MS.length - 1)];
    await sleep(Math.min(wait, Math.max(0, MAX_TOTAL_MS - elapsed)));
  }
}

const executionMs = Date.now() - t0;
if (!fetchMode) {
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      notebookUrl,
      activeSourceCount,
      hasSources,
      activeReportCount,
      hasReports,
      seedMode,
      reason: `RSS 재시도 종료(${lastError || 'unknown'})`,
      attemptsUsed,
      retryStrategy: 'retry-until-success-or-timebox',
      executionMs,
      lookbackHours,
      rssUrl,
    },
  };
}

if (!entries.length) {
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      notebookUrl,
      activeSourceCount,
      hasSources,
      activeReportCount,
      hasReports,
      seedMode,
      reason: `RSS 성공 but entry 없음(mode=${fetchMode})`,
      attemptsUsed,
      executionMs,
      entriesTotal: 0,
      cutoffIso: CUTOFF_ISO,
      lookbackHours,
      rssUrl,
    },
  };
}

const validEntries = [];
let skippedShorts = 0;
let skippedNoUrl = 0;
let skippedInvalidDate = 0;
let skippedOld = 0;
let latestPublishedMs = null;

for (const e of entries) {
  const url = e.videoUrl || `https://www.youtube.com/watch?v=${e.videoId}`;
  if (!url) {
    skippedNoUrl += 1;
    continue;
  }
  if (url.includes('/shorts/')) {
    skippedShorts += 1;
    continue;
  }
  const ts = Date.parse(e.publishedAt || '');
  if (!Number.isFinite(ts)) {
    skippedInvalidDate += 1;
    continue;
  }
  if (latestPublishedMs === null || ts > latestPublishedMs) {
    latestPublishedMs = ts;
  }
  validEntries.push({
    videoUrl: url,
    title: e.title || '',
    publishedAt: e.publishedAt || '',
    publishedMs: ts,
  });
}

if (!validEntries.length) {
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      notebookUrl,
      activeSourceCount,
      hasSources,
      activeReportCount,
      hasReports,
      seedMode,
      reason: `유효한 영상 없음(mode=${fetchMode})`,
      attemptsUsed,
      executionMs,
      entriesTotal: entries.length,
      latestPublishedAt: latestPublishedMs === null ? null : new Date(latestPublishedMs).toISOString(),
      skippedShorts,
      skippedInvalidDate,
      skippedNoUrl,
      rssUrl,
    },
  };
}

if (!hasSources) {
  let selected = validEntries[0];
  for (let i = 1; i < validEntries.length; i++) {
    const current = validEntries[i];
    if (current.publishedMs > selected.publishedMs) {
      selected = current;
    }
  }
  return {
    json: {
      videoUrl: selected.videoUrl,
      title: selected.title,
      publishedAt: selected.publishedAt,
      channelId,
      channelName,
      notebookUrl,
      activeSourceCount,
      hasSources,
      activeReportCount,
      hasReports,
      seedMode,
      attemptsUsed,
      fetchMode,
      executionMs,
      entriesTotal: entries.length,
      validEntriesCount: validEntries.length,
      cutoffIso: CUTOFF_ISO,
      lookbackHours,
      latestPublishedAt: latestPublishedMs === null ? null : new Date(latestPublishedMs).toISOString(),
      freshCount: 1,
      ignoredLookback: true,
      selectedStrategy: 'latest-only-empty-notebook',
      forceAutoReport: false,
    },
  };
}

const fresh = [];
for (const e of validEntries) {
  if (e.publishedMs < CUTOFF_MS) {
    skippedOld += 1;
    continue;
  }
  fresh.push(e);
}

if (!fresh.length) {
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      notebookUrl,
      activeSourceCount,
      hasSources,
      activeReportCount,
      hasReports,
      seedMode,
      reason: `새 영상 없음(최근 ${lookbackHours}시간, mode=${fetchMode})`,
      attemptsUsed,
      executionMs,
      entriesTotal: entries.length,
      validEntriesCount: validEntries.length,
      latestPublishedAt: latestPublishedMs === null ? null : new Date(latestPublishedMs).toISOString(),
      cutoffIso: CUTOFF_ISO,
      lookbackHours,
      skippedOld,
      skippedShorts,
      skippedInvalidDate,
      skippedNoUrl,
      rssUrl,
    },
  };
}

let selected = fresh[0];
for (let i = 1; i < fresh.length; i++) {
  const current = fresh[i];
  if (current.publishedMs > selected.publishedMs) {
    selected = current;
  }
}

return {
  json: {
    videoUrl: selected.videoUrl,
    title: selected.title,
    publishedAt: selected.publishedAt,
    channelId,
    channelName,
    notebookUrl,
    activeSourceCount,
    hasSources,
    activeReportCount,
    hasReports,
    seedMode,
    attemptsUsed,
    fetchMode,
    executionMs,
    entriesTotal: entries.length,
    validEntriesCount: validEntries.length,
    cutoffIso: CUTOFF_ISO,
    lookbackHours,
    latestPublishedAt: latestPublishedMs === null ? null : new Date(latestPublishedMs).toISOString(),
    freshCount: fresh.length,
    ignoredLookback: false,
    selectedStrategy: 'latest-only-per-channel',
    forceAutoReport: false,
  },
};

// 결과 로깅 + 자동 보고서(WF-06) 트리거
const result = $input.item.json;
const source = $('RSS 조회 + 새 영상 필터링').item.json || {};
const shouldAutoReportOnDuplicate = Boolean(result.duplicate && !source.hasReports && source.videoUrl);

if (result.duplicate) {
  console.log(`[WF-09] 중복 건너뜀 channel=${source.channelId || '(unknown)'} seedMode=${source.seedMode || '(unknown)'} notebook=${source.notebookUrl || '(unknown)'} hasReports=${source.hasReports}`);
} else if (result.added) {
  console.log(`[WF-09] 소스 추가 완료 channel=${source.channelId || '(unknown)'} seedMode=${source.seedMode || '(unknown)'} notebook=${source.notebookUrl || '(unknown)'} sourceCountBefore=${source.activeSourceCount ?? '(unknown)'} cleaned=${result.cleaned_up}`);
}

if (result.added || shouldAutoReportOnDuplicate) {
  const payload = {
    channel_id: source.channelId || '',
    channel_name: source.channelName || '',
    source_url: source.videoUrl || '',
    source_title: source.title || '',
  };

  if (!payload.channel_id || !payload.source_url) {
    result.auto_report_status = 'skipped';
    result.auto_report_reason = 'missing channel_id or source_url';
    console.warn('[WF-09] auto-report skipped: missing channel_id or source_url');
  } else {
    try {
      const parsed = await this.helpers.httpRequest({
        method: 'POST',
        url: 'http://messenger-gateway:8080/internal/auto-report',
        headers: {
          'Content-Type': 'application/json',
          'X-Internal-Secret': $env.GATEWAY_INTERNAL_SECRET,
        },
        body: payload,
        json: true,
        timeout: 30000,
      });

      result.auto_report_status = 'triggered';
      result.auto_report_job_id = parsed.job_id || '';
      const shortId = (result.auto_report_job_id || '').slice(0, 8);
      const triggerReason = shouldAutoReportOnDuplicate ? 'duplicate-no-report' : 'source-added';
      console.log(`[WF-09] auto-report triggered channel=${payload.channel_id} seedMode=${source.seedMode || '(unknown)'} reason=${triggerReason} job=${shortId || '(unknown)'}`);
    } catch (e) {
      const msg = e && e.message ? e.message : String(e);
      result.auto_report_status = 'failed';
      result.auto_report_error = msg.slice(0, 300);
      console.error(`[WF-09] auto-report trigger error channel=${payload.channel_id} seedMode=${source.seedMode || '(unknown)'}: ${result.auto_report_error}`);
    }
  }
} else if (result.error) {
  console.error(`[WF-09] 소스 추가 실패 channel=${source.channelId || '(unknown)'} seedMode=${source.seedMode || '(unknown)'}: ${result.error}`);
} else {
  result.auto_report_status = result.auto_report_status || 'skipped';
}

return { json: result };
